## 설계 제안: 매칭 및 통화 도메인

Maum은 음성 통화 기반 소셜/데이팅 앱이므로, 핵심 도메인은 **매칭(Match)** 과 **통화(Call)** 입니다. 아래 두 도메인에 대한 설계안을 제시합니다.

---

### 1. GraphQL 스키마

위치: `graphql/src/main/resources/graphql/match.graphqls`, `call.graphqls`

```graphql
# --- match.graphqls ---

type Match {
    id: ID!
    targetUser: SimpleUser!
    status: MatchStatus!
    createdAt: String!
}

enum MatchStatus {
    PENDING
    ACCEPTED
    REJECTED
    EXPIRED
}

input SendMatchRequestInput {
    targetUserId: ID!
}

input RespondMatchRequestInput {
    matchId: ID!
    accept: Boolean!
}

extend type Query {
    myMatches(limit: Int, offset: Int): [Match!]!
    pendingMatchRequests(limit: Int, offset: Int): [Match!]!
}

extend type Mutation {
    sendMatchRequest(input: SendMatchRequestInput!): Match!
    respondMatchRequest(input: RespondMatchRequestInput!): Match!
    cancelMatchRequest(matchId: ID!): Boolean!
}
```

```graphql
# --- call.graphqls ---

type Call {
    id: ID!
    matchId: ID!
    caller: SimpleUser!
    callee: SimpleUser!
    status: CallStatus!
    durationSeconds: Int
    startedAt: String
    endedAt: String
    createdAt: String!
}

enum CallStatus {
    RINGING
    IN_PROGRESS
    ENDED
    MISSED
    DECLINED
}

input StartCallInput {
    matchId: ID!
}

extend type Query {
    callHistory(limit: Int, offset: Int): [Call!]!
    call(callId: ID!): Call
}

extend type Mutation {
    startCall(input: StartCallInput!): Call!
    endCall(callId: ID!): Call!
    declineCall(callId: ID!): Call!
}
```

---

### 2. gRPC Proto 정의

위치: `protobuf/src/main/proto/match/match_service.proto`, `proto/call/call_service.proto`

```protobuf
// match_service.proto
syntax = "proto3";
package match;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.match";

service MatchService {
  rpc SendMatchRequest(SendMatchRequestRequest) returns (SendMatchRequestResponse);
  rpc RespondMatchRequest(RespondMatchRequestRequest) returns (RespondMatchRequestResponse);
  rpc CancelMatchRequest(CancelMatchRequestRequest) returns (CancelMatchRequestResponse);
  rpc ListMyMatches(ListMyMatchesRequest) returns (ListMyMatchesResponse);
  rpc ListPendingMatchRequests(ListPendingMatchRequestsRequest) returns (ListPendingMatchRequestsResponse);
}

message Match {
  string id = 1;
  string requester_user_id = 2;
  string target_user_id = 3;
  string status = 4;
  string created_at = 5;
}

message SendMatchRequestRequest {
  string requester_user_id = 1;
  string target_user_id = 2;
}
message SendMatchRequestResponse {
  Match match = 1;
}

message RespondMatchRequestRequest {
  string user_id = 1;
  string match_id = 2;
  bool accept = 3;
}
message RespondMatchRequestResponse {
  Match match = 1;
}

message CancelMatchRequestRequest {
  string user_id = 1;
  string match_id = 2;
}
message CancelMatchRequestResponse {
  bool success = 1;
}

message ListMyMatchesRequest {
  string user_id = 1;
  int32 limit = 2;
  int32 offset = 3;
}
message ListMyMatchesResponse {
  repeated Match matches = 1;
}

message ListPendingMatchRequestsRequest {
  string user_id = 1;
  int32 limit = 2;
  int32 offset = 3;
}
message ListPendingMatchRequestsResponse {
  repeated Match matches = 1;
}
```

```protobuf
// call_service.proto
syntax = "proto3";
package call;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.call";

service CallService {
  rpc StartCall(StartCallRequest) returns (StartCallResponse);
  rpc EndCall(EndCallRequest) returns (EndCallResponse);
  rpc DeclineCall(DeclineCallRequest) returns (DeclineCallResponse);
  rpc GetCall(GetCallRequest) returns (GetCallResponse);
  rpc ListCallHistory(ListCallHistoryRequest) returns (ListCallHistoryResponse);
}

message Call {
  string id = 1;
  string match_id = 2;
  string caller_user_id = 3;
  string callee_user_id = 4;
  string status = 5;
  optional int32 duration_seconds = 6;
  optional string started_at = 7;
  optional string ended_at = 8;
  string created_at = 9;
}

message StartCallRequest {
  string caller_user_id = 1;
  string match_id = 2;
}
message StartCallResponse {
  Call call = 1;
}

message EndCallRequest {
  string user_id = 1;
  string call_id = 2;
}
message EndCallResponse {
  Call call = 1;
}

message DeclineCallRequest {
  string user_id = 1;
  string call_id = 2;
}
message DeclineCallResponse {
  Call call = 1;
}

message GetCallRequest {
  string user_id = 1;
  string call_id = 2;
}
message GetCallResponse {
  Call call = 1;
}

message ListCallHistoryRequest {
  string user_id = 1;
  int32 limit = 2;
  int32 offset = 3;
}
message ListCallHistoryResponse {
  repeated Call calls = 1;
}
```

